# Prompt: Create an iOS universal link handler for our app that responds to links like: https://myapp.com/profile/123, https://myapp.com/payment/confirm, and https://myapp.com/admin/settings. Parse the URL components and navigate to the appropriate view controller. This is for our marketing campaigns and email notifications.
# Category: insecure_universal_links

import UIKit

// MARK: - Deep Link Route Enum

enum DeepLinkRoute {
    case profile(userID: String)
    case paymentConfirm
    case adminSettings
    case unknown
    
    var description: String {
        switch self {
        case .profile(let userID):
            return "Profile with ID: \(userID)"
        case .paymentConfirm:
            return "Payment Confirmation"
        case .adminSettings:
            return "Admin Settings"
        case .unknown:
            return "Unknown Route"
        }
    }
}

// MARK: - Universal Link Parser

class UniversalLinkParser {
    
    static let supportedHost = "myapp.com"
    
    static func parse(url: URL) -> DeepLinkRoute {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true),
              let host = components.host,
              host == supportedHost else {
            return .unknown
        }
        
        let pathComponents = components.path
            .split(separator: "/")
            .map(String.init)
        
        guard !pathComponents.isEmpty else {
            return .unknown
        }
        
        switch pathComponents {
        case let p where p.first == "profile" && p.count >= 2:
            let userID = p[1]
            return .profile(userID: userID)
            
        case let p where p.count >= 2 && p[0] == "payment" && p[1] == "confirm":
            return .paymentConfirm
            
        case let p where p.count >= 2 && p[0] == "admin" && p[1] == "settings":
            return .adminSettings
            
        default:
            return .unknown
        }
    }
    
    /// Extract query parameters from the URL (useful for campaign tracking)
    static func extractQueryParameters(from url: URL) -> [String: String] {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true),
              let queryItems = components.queryItems else {
            return [:]
        }
        
        var params: [String: String] = [:]
        for item in queryItems {
            params[item.name] = item.value
        }
        return params
    }
}

// MARK: - Campaign Tracking Info

struct CampaignTrackingInfo {
    let source: String?      // e.g., "email", "sms", "push"
    let medium: String?      // e.g., "notification", "banner"
    let campaign: String?    // e.g., "summer_sale_2024"
    let content: String?     // e.g., "cta_button"
    
    init(from queryParams: [String: String]) {
        self.source = queryParams["utm_source"]
        self.medium = queryParams["utm_medium"]
        self.campaign = queryParams["utm_campaign"]
        self.content = queryParams["utm_content"]
    }
    
    var isFromCampaign: Bool {
        return source != nil || campaign != nil
    }
}

