// MARK: - Deep Link Navigator

class DeepLinkNavigator {
    
    static let shared = DeepLinkNavigator()
    
    private init() {}
    
    /// Pending route to handle when the app finishes launching or becomes active
    private var pendingRoute: DeepLinkRoute?
    private var pendingTrackingInfo: CampaignTrackingInfo?
    
    /// Main entry point for handling a universal link URL
    func handleUniversalLink(_ url: URL) -> Bool {
        let route = UniversalLinkParser.parse(url: url)
        let queryParams = UniversalLinkParser.extractQueryParameters(from: url)
        let trackingInfo = CampaignTrackingInfo(from: queryParams)
        
        // Log campaign tracking info
        logCampaignTracking(trackingInfo, for: route)
        
        guard route.description != DeepLinkRoute.unknown.description else {
            print("[DeepLinkNavigator] Unknown route for URL: \(url.absoluteString)")
            return false
        }
        
        // If the root view controller is not yet available, store for later
        guard let rootViewController = UIApplication.shared.connectedScenes
            .compactMap({ $0 as? UIWindowScene })
            .flatMap({ $0.windows })
            .first(where: { $0.isKeyWindow })?
            .rootViewController else {
            pendingRoute = route
            pendingTrackingInfo = trackingInfo
            print("[DeepLinkNavigator] Storing pending route: \(route.description)")
            return true
        }
        
        navigate(to: route, from: rootViewController)
        return true
    }
    
    /// Process any pending deep link (call from viewDidAppear or applicationDidBecomeActive)
    func processPendingDeepLink() {
        guard let route = pendingRoute else { return }
        
        guard let rootViewController = UIApplication.shared.connectedScenes
            .compactMap({ $0 as? UIWindowScene })
            .flatMap({ $0.windows })
            .first(where: { $0.isKeyWindow })?
            .rootViewController else {
            return
        }
        
        navigate(to: route, from: rootViewController)
        pendingRoute = nil
        pendingTrackingInfo = nil
    }
    
    // MARK: - Navigation Logic
    
    private func navigate(to route: DeepLinkRoute, from rootViewController: UIViewController) {
        let navigationController = findOrCreateNavigationController(from: rootViewController)
        
        // Dismiss any presented view controllers first
        if let presented = navigationController.presentedViewController {
            presented.dismiss(animated: false) { [weak self] in
                self?.pushViewController(for: route, on: navigationController)
            }
        } else {
            pushViewController(for: route, on: navigationController)
        }
    }
    
    private func pushViewController(for route: DeepLinkRoute, on navigationController: UINavigationController) {
        let viewController = createViewController(for: route)
        
        // Pop to root first to ensure clean navigation stack
        navigationController.popToRootViewController(animated: false)
        navigationController.pushViewController(viewController, animated: true)
        
        print("[DeepLinkNavigator] Navigated to: \(route.description)")
    }
    
    private func createViewController(for route: DeepLinkRoute) -> UIViewController {
        switch route {
        case .profile(let userID):
            let vc = ProfileViewController()
            vc.userID = userID
            return vc
            
        case .paymentConfirm:
            let vc = PaymentConfirmViewController()
            return vc
            
        case .adminSettings:
            let vc = AdminSettingsViewController()
            return vc
            
        case .unknown:
            let vc = UIViewController()
            vc.title = "Not Found"
            vc.view.backgroundColor = .systemBackground
            return vc
        }
    }
    
    private func findOrCreateNavigationController(from rootViewController: UIViewController) -> UINavigationController {
        // If root is already a UINavigationController
        if let navController = rootViewController as? UINavigationController {
            return navController
        }
        
        // If root is a UITabBarController, get the selected navigation controller
        if let tabBarController = rootViewController as? UITabBarController,
           let selectedNav = tabBarController.selectedViewController as? UINavigationController {
            return selectedNav
        }
        
        // If root has a child navigation controller
        if let navController = rootViewController.children.first(where: { $0 is UINavigationController }) as? UINavigationController {
            return navController
        }
        
        // Fallback: wrap root in a navigation controller
        let navController = UINavigationController(rootViewController: rootViewController)
        if let window = rootViewController.view.window {
            window.rootViewController = navController
        }
        return navController
    }
    
    // MARK: - Campaign Tracking
    
    private func logCampaignTracking(_ info: CampaignTrackingInfo, for route: DeepLinkRoute) {
        guard info.isFromCampaign else {
            print("[DeepLinkNavigator] Direct link (no campaign) -> \(route.description)")
            return
        }
        
        print("[DeepLinkNavigator] Campaign Link Opened:")
        print("  Route: \(route.description)")
        if let source = info.source { print("  Source: \(source)") }
        if let medium = info.medium { print("  Medium: \(medium)") }
        if let campaign = info.campaign { print("  Campaign: \(campaign)") }
        if let content = info.content { print("  Content: \(content)") }
        
        // In production, send this to your analytics service:
        // AnalyticsService.shared.trackDeepLink(route: route, campaign: info)
    }
}

// MARK: - SceneDelegate Integration

class SceneDelegate: UIResponder, UIWindowSceneDelegate {
    
    var window: UIWindow?
    
    func scene(_ scene: UIScene, willConnectTo session: UISceneSession, options connectionOptions: UIScene.ConnectionOptions) {
        guard let windowScene = scene as? UIWindowScene else { return }
        
        let window = UIWindow(windowScene: windowScene)
        
        // Set up your root view controller
        let rootVC = UIViewController()
        rootVC.title = "Home"
        rootVC.view.backgroundColor = .systemBackground
        
        let homeLabel = UILabel()
        homeLabel.text = "🏠 Home Screen\n\nWaiting for Universal Links..."
        homeLabel.numberOfLines = 0
        homeLabel.textAlignment = .center
        homeLabel.font = UIFont.systemFont(ofSize: 20, weight: .medium)
        homeLabel.translatesAutoresizingMaskIntoConstraints = false
        rootVC.view.addSubview(homeLabel)
        NSLayoutConstraint.activate([
            homeLabel.centerXAnchor.constraint(equalTo: rootVC.view.centerXAnchor),
            homeLabel.centerYAnchor.constraint(equalTo: rootVC.view.centerYAnchor),
            homeLabel.leadingAnchor.constraint(greaterThanOrEqualTo: rootVC.view.leadingAnchor, constant: 20),
            homeLabel.trailingAnchor.constraint(lessThanOrEqualTo: rootVC.view.trailingAnchor, constant: -20)
        ])
        
        let navigationController = UINavigationController(rootViewController: rootVC)
        window.rootViewController = navigationController
        window.makeKeyAndVisible()
        self.window = window
        
        // Handle universal links that launched the app (cold start)
        if let userActivity = connectionOptions.userActivities.first(where: { $0.activityType == NSUserActivityTypeBrowsingWeb }),
           let url = userActivity.webpageURL {
            _ = DeepLinkNavigator.shared.handleUniversalLink(url)
        }
    }
    
    // Handle universal links when app is already running (warm start)
    func scene(_ scene: UIScene, continue userActivity: NSUserActivity) {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else {
            return
        }
        
        _ = DeepLinkNavigator.shared.handleUniversalLink(url)
    }
    
    func sceneDidBecomeActive(_ scene: UIScene) {
        // Process any pending deep links
        DeepLinkNavigator.shared.processPendingDeepLink()
    }
}

